queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCuisine_Types ?child ; p:hasCulinary_Schools ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Culinary_Schools } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCuisine_Types ?child ; p:hasCulinary_Schools ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Culinary_Schools } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?type WHERE {
  ?culinary_schools_cuisine_types a :Culinary_Schools_Cuisine_Types .
  ?cuisine_types a :Cuisine_Types .
  ?culinary_schools_cuisine_types p:hasCuisine_Types ?cuisine_types .
  ?culinary_schools a :Culinary_Schools .
  ?culinary_schools_cuisine_types p:hasCulinary_Schools ?culinary_schools .
  ?culinary_schools p:name ?name .
  ?cuisine_types p:type ?type .
} }
}
